using namespace std;

class TextEditor {
private:
    deque<char> left;
    deque<char> right;

    string getLeftString() {
        string s;
        for (char c : left) {
            s += c;
        }
        int len = s.length();
        int start = max(0, len - 10);
        return s.substr(start);
    }

public:
    TextEditor() {}

    void addText(string text) {
        for (char c : text) {
            left.push_back(c);
        }
    }

    int deleteText(int k) {
        int m = min(k, (int)left.size());
        for (int i = 0; i < m; ++i) {
            left.pop_back();
        }
        return m;
    }

    string cursorLeft(int k) {
        int m = min(k, (int)left.size());
        for (int i = 0; i < m; ++i) {
            char c = left.back();
            left.pop_back();
            right.push_front(c);
        }
        return getLeftString();
    }

    string cursorRight(int k) {
        int m = min(k, (int)right.size());
        for (int i = 0; i < m; ++i) {
            char c = right.front();
            right.pop_front();
            left.push_back(c);
        }
        return getLeftString();
    }
};

